import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { loginSchema } from './login-schema';

export const GlassLogin = () => {
  const { register, handleSubmit } = useForm({ resolver: zodResolver(loginSchema) });
  return (
    <div className="backdrop-blur-md bg-white/30 p-8 rounded-2xl border border-white/20">
      <h2 className="text-2xl font-bold mb-4">Welcome Back</h2>
      <form onSubmit={handleSubmit((data) => console.log(data))}>
        <input {...register('email')} className="block w-full mb-2 p-2 rounded" placeholder="Email" />
        <button type="submit" className="w-full bg-blue-600 text-white p-2 rounded">Login</button>
      </form>
    </div>
  );
};

import { z } from 'zod';
export const loginSchema = z.object({
  email: z.string().email(),
  password: z.string().min(8)
});

import { Menu, User, Bell } from 'lucide-react';

export const Navbar = () => (
  <nav className="flex items-center justify-between p-4 bg-gray-900 text-white">
    <div className="font-bold text-xl">DevDocs</div>
    <div className="flex gap-4">
      <Bell size={20} />
      <User size={20} />
      <Menu size={20} />
    </div>
  </nav>
);

import { motion } from 'framer-motion';

export const Hero = () => (
  <section className="py-20 text-center bg-gradient-to-b from-blue-50 to-white">
    <motion.h1 initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-5xl font-extrabold">
      Build Faster with Chaicode
    </motion.h1>
    <p className="mt-4 text-gray-600">The ultimate CLI for modern backend developers.</p>
  </section>
);

import { useReactTable, getCoreRowModel, flexRender } from '@tanstack/react-table';

export const DataTable = ({ data, columns }) => {
  const table = useReactTable({ data, columns, getCoreRowModel: getCoreRowModel() });
  return (
    <table className="min-w-full divide-y divide-gray-200">
      <thead>{/* Render Headers */}</thead>
      <tbody>{/* Render Rows */}</tbody>
    </table>
  );
};

import { ShieldCheck } from 'lucide-react';

export const AuthStatus = ({ isAuthed }) => (
  <div className="flex items-center gap-2 p-3 rounded-lg bg-green-100 text-green-800">
    <ShieldCheck size={18} />
    <span>{isAuthed ? 'Secure Connection Active' : 'Not Authenticated'}</span>
  </div>
);
